mapper.select:
SELECT s.*, c.category_name as categoryName FROM service_definition s LEFT JOIN service_category c ON s.category_id = c.id WHERE s.status = 'ACTIVE'
AND (s.service_name LIKE CONCAT('%', #{keyword}, '%') OR s.service_code LIKE CONCAT('%', #{keyword}, '%'))
AND s.service_type = #{serviceType}
AND s.category_id = #{categoryId}
ORDER BY s.created_at DESC
